node -e 'const fs=require("fs");
const path=require("path");
const os=require("os");
const {execFileSync}=require("child_process");
const cli=path.join(process.cwd(),"bin","cli.js");
const tmp=path.join(os.tmpdir(),"fulfill-wave-accept-"+process.pid+".json");
const fixture={
  warehouses:[{id:"W1",distance:1,lots:[{sku:"SKU1",lot:"L1",qty:10,expires:"2027-01-01"}]}],
  orders:[{id:"O1",priority:5,submitted_at:"2026-01-01T00:00:00Z",lines:[{sku:"SKU1",qty:4,single_warehouse:false}]}]
};
const raw=JSON.stringify(fixture);
fs.writeFileSync(tmp,raw);
try{
  const out=execFileSync("node",[cli,"fulfill-wave","--input",tmp],{encoding:"utf8"});
  const after=fs.readFileSync(tmp,"utf8");
  if(after!==raw){throw new Error("input file was mutated")}
  const data=JSON.parse(out);
  const keys=Object.keys(data).sort().join(",");
  if(keys!=="accepted,rejected,remaining"){throw new Error("unexpected top-level keys: "+keys)}
  if(data.rejected.length!==0){throw new Error("expected no rejections")}
  if(data.accepted.length!==1||data.accepted[0].id!=="O1"){throw new Error("unexpected accepted rows: "+JSON.stringify(data.accepted))}
  const allocs=data.accepted[0].allocations;
  if(allocs.length!==1||allocs[0].sku!=="SKU1"||allocs[0].warehouse!=="W1"||allocs[0].lot!=="L1"||allocs[0].qty!==4){
    throw new Error("unexpected allocation: "+JSON.stringify(allocs));
  }
  if(data.remaining.length!==1||data.remaining[0].qty!==6||data.remaining[0].lot!=="L1"){
    throw new Error("unexpected remaining: "+JSON.stringify(data.remaining));
  }
  process.stdout.write("MECH_ACCEPT_OK\n");
}finally{
  fs.unlinkSync(tmp);
}'

node -e 'const fs=require("fs");
const path=require("path");
const os=require("os");
const {execFileSync}=require("child_process");
const cli=path.join(process.cwd(),"bin","cli.js");
const tmp=path.join(os.tmpdir(),"fulfill-wave-reject-"+process.pid+".json");
const fixture={
  warehouses:[{id:"W1",distance:1,lots:[{sku:"SKU1",lot:"L1",qty:5,expires:"2027-01-01"}]}],
  orders:[{id:"O2",priority:5,submitted_at:"2026-01-01T00:00:00Z",lines:[
    {sku:"SKU1",qty:3,single_warehouse:false},
    {sku:"SKU1",qty:10,single_warehouse:false}
  ]}]
};
fs.writeFileSync(tmp,JSON.stringify(fixture));
try{
  const out=execFileSync("node",[cli,"fulfill-wave","--input",tmp],{encoding:"utf8"});
  const data=JSON.parse(out);
  if(data.accepted.length!==0){throw new Error("expected zero accepted rows: "+JSON.stringify(data.accepted))}
  if(data.rejected.length!==1||data.rejected[0].id!=="O2"||data.rejected[0].reason!=="insufficient_stock"){
    throw new Error("unexpected rejected rows: "+JSON.stringify(data.rejected));
  }
  const rejectedKeys=Object.keys(data.rejected[0]).sort().join(",");
  if(rejectedKeys!=="id,reason"){throw new Error("unexpected rejected row keys: "+rejectedKeys)}
  if(data.remaining.length!==1||data.remaining[0].qty!==5){
    throw new Error("stock was not fully restored after rejection: "+JSON.stringify(data.remaining));
  }
  process.stdout.write("MECH_REJECT_OK\n");
}finally{
  fs.unlinkSync(tmp);
}'

node -e 'const fs=require("fs");
const path=require("path");
const os=require("os");
const {spawnSync}=require("child_process");
const cli=path.join(process.cwd(),"bin","cli.js");
const tmp=path.join(os.tmpdir(),"fulfill-wave-invalid-"+process.pid+".json");
const fixture={
  warehouses:[{id:"W1",distance:1,lots:[{sku:"SKU1",lot:"L1",qty:-5,expires:"2027-01-01"}]}],
  orders:[]
};
fs.writeFileSync(tmp,JSON.stringify(fixture));
try{
  const res=spawnSync("node",[cli,"fulfill-wave","--input",tmp],{encoding:"utf8"});
  if(res.status!==2){throw new Error("expected exit 2, got "+res.status)}
  if(res.stdout&&res.stdout.length>0){throw new Error("expected empty stdout, got: "+res.stdout)}
  let parsed;
  try{parsed=JSON.parse(res.stderr)}catch(e){throw new Error("stderr was not parseable JSON: "+res.stderr)}
  if(parsed===null||Array.isArray(parsed)||typeof parsed!=="object"){
    throw new Error("stderr JSON must be a non-null, non-array object");
  }
  process.stdout.write("MECH_INVALID_OK\n");
}finally{
  fs.unlinkSync(tmp);
}'
